# pytest# from ragas.metrics import LLMContextPrecisionWithoutReferenceimport osimport pytestfrom dotenv import load_dotenvfrom langchain_anthropic import ChatAnthropicfrom ragas import SingleTurnSamplefrom ragas.llms import LangchainLLMWrapperfrom ragas.metrics._context_precision import LLMContextPrecisionWithoutReferenceload_dotenv()@pytest.mark.asyncioasync def test_context_precision():    # create object of class for specific metric    llm_model = ChatAnthropic(temperature=0, model_name="claude-3-5-haiku-latest")    langchain_llm = LangchainLLMWrapper(llm_model)    context_precision = LLMContextPrecisionWithoutReference(llm = langchain_llm)    # feed data    sample = SingleTurnSample(        user_input = "How many articles are present in the Selenium WebDriver course?",        response = "There are **63 articles** included in the Selenium Webdriver course.",        retrieved_contexts= [            "Wish you all the Best! See you all in the course with above topics :)\n\nWho this course is for:\nAutomation Engineers\nSoftware Engineers\nManual testers\nSoftware developers",            "What you'll learn\n*****By the end of this course,You will be Mastered on Selenium Webdriver with strong Core JAVA basics\n****You will gain the ability to design PAGEOBJECT, DATADRIVEN&HYBRID Automation FRAMEWORKS from scratch\n*** InDepth understanding of real time Selenium CHALLENGES with 100 + examples\n*Complete knowledge on TestNG, MAVEN,ANT, JENKINS,LOG4J, CUCUMBER, HTML REPORTS,EXCEL API, GRID PARALLEL TESTING",        ]    )    # output score    score = await context_precision.single_turn_ascore(sample)    print(f"The score is: {score}")    assert score is not None    assert 0 <= score <= 1